'use client';

import { useEffect } from 'react';
import { usePathname } from 'next/navigation';

export default function AnimationManager() {
  const pathname = usePathname();

  useEffect(() => {
    // Select all elements that should be animated
    const selectors = [
      '.product-card',
      '.fade-in-up',
      '.fade-in-left',
      '.fade-in-right',
      '.cat-section-title',
      '.section-header h2',
      '.step-item',
      '[data-animate]'
    ];

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const el = entry.target;
            
            // Add visibility classes based on what's present
            if (el.classList.contains('product-card')) {
              el.classList.add('card-visible');
            }
            
            if (el.classList.contains('fade-in-up') || 
                el.classList.contains('fade-in-left') || 
                el.classList.contains('fade-in-right') ||
                el.classList.contains('cat-section-title') ||
                el.classList.contains('step-item') ||
                el.querySelector('h2')) {
              el.classList.add('visible');
            }
            
            if (el.hasAttribute('data-animate')) {
              el.classList.add('animated');
            }
            
            // Stop observing after animation is triggered
            observer.unobserve(el);
          }
        });
      },
      {
        threshold: 0.1, // Trigger when 10% is visible
        rootMargin: '0px 0px -50px 0px' // Trigger slightly before it enters the viewport
      }
    );

    const observeElements = () => {
      selectors.forEach(selector => {
        document.querySelectorAll(selector).forEach(el => {
          // If already visible (e.g. from previous route), skip or re-observe
          if (!el.classList.contains('visible') && 
              !el.classList.contains('card-visible') && 
              !el.classList.contains('animated')) {
            
            // Check if already in viewport
            const rect = el.getBoundingClientRect();
            const isInViewport = rect.top < window.innerHeight && rect.bottom >= 0;
            
            if (isInViewport) {
              // Trigger immediately if in viewport
              if (el.classList.contains('product-card')) el.classList.add('card-visible');
              if (el.classList.contains('fade-in-up') || 
                  el.classList.contains('fade-in-left') || 
                  el.classList.contains('fade-in-right') ||
                  el.classList.contains('cat-section-title') ||
                  el.classList.contains('step-item')) {
                el.classList.add('visible');
              }
              if (el.hasAttribute('data-animate')) el.classList.add('animated');
            } else {
              observer.observe(el);
            }
          }
        });
      });
    };

    // Initial check
    observeElements();

    // Re-check when the path changes (Next.js route changes)
    // We use a small timeout to ensure the DOM has updated
    const timer = setTimeout(observeElements, 100);

    return () => {
      observer.disconnect();
      clearTimeout(timer);
    };
  }, [pathname]);

  return null; // This component doesn't render anything
}
